solution_code:
#include <iostream>

namespace {
    int total = 0;
    void record(int v) { total += v; }
    int getSum()       { return total; }
}

int main() {
    int a{}, b{}, c{};
    std::cin >> a >> b >> c;

    record(a);
    record(b);
    record(c);

    std::cout << "Sum: " << getSum() << "\n";
    return 0;
}

